<?php
require_once '../config/Database.php';
$db=(new Database())->connect();$slug=trim($_GET['hotel']??'');$idEncuesta=(int)($_GET['encuesta']??0);$ok=false;$err='';$promedio=0;$mostrarRedes=false;$redes=[];
$st=$db->prepare("SELECT e.*,h.id_hotel,h.nombre_comercial,h.slug FROM encuestas e JOIN hoteles h ON h.id_hotel=e.id_hotel WHERE e.id_encuesta=? AND h.slug=? AND e.estado='ACTIVA' LIMIT 1");$st->execute([$idEncuesta,$slug]);$encuesta=$st->fetch(PDO::FETCH_ASSOC);
if(!$encuesta){http_response_code(404);die('Encuesta no disponible.');}
$st=$db->prepare("SELECT * FROM encuesta_areas WHERE id_encuesta=? AND estado='ACTIVA' ORDER BY orden,id_area");$st->execute([$idEncuesta]);$areas=$st->fetchAll(PDO::FETCH_ASSOC);
if($_SERVER['REQUEST_METHOD']==='POST'){
 try{
  $califs=[];foreach($areas as $a){$v=(int)($_POST['area'][$a['id_area']]??0);if($v<1||$v>5)throw new Exception('Califica todas las áreas.');$califs[(int)$a['id_area']]=$v;}
  $promedio=array_sum($califs)/count($califs);$mostrarRedes=$promedio>=(float)$encuesta['umbral_publicar'];
  $db->beginTransaction();$db->prepare("INSERT INTO encuesta_respuestas(id_encuesta,id_reserva,nombre_cliente,email_cliente,comentario,promedio,mostro_redes) VALUES(?,?,?,?,?,?,?)")->execute([$idEncuesta,($_POST['id_reserva']??'')!==''?(int)$_POST['id_reserva']:null,trim($_POST['nombre']??''),trim($_POST['email']??''),trim($_POST['comentario']??''),$promedio,$mostrarRedes?1:0]);$idR=(int)$db->lastInsertId();$stD=$db->prepare("INSERT INTO encuesta_respuesta_detalle(id_respuesta,id_area,calificacion) VALUES(?,?,?)");foreach($califs as $idA=>$v)$stD->execute([$idR,$idA,$v]);$db->commit();$ok=true;
  $st=$db->prepare("SELECT * FROM hotel_redes_sociales WHERE id_hotel=?");$st->execute([(int)$encuesta['id_hotel']]);$redes=$st->fetch(PDO::FETCH_ASSOC)?:[];
  $st=$db->prepare("SELECT red FROM encuesta_redes WHERE id_encuesta=?");$st->execute([$idEncuesta]);$redesPermitidas=array_column($st->fetchAll(PDO::FETCH_ASSOC),'red');
 }catch(Throwable $e){if($db->inTransaction())$db->rollBack();$err=$e->getMessage();}
}
?><!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=htmlspecialchars($encuesta['titulo'])?></title><link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600;700;800&display=swap" rel="stylesheet"><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css"><style>*{box-sizing:border-box}body{margin:0;background:linear-gradient(180deg,#eef5fb,#f8fafc);font-family:Poppins;color:#152231}.wrap{max-width:760px;margin:35px auto;padding:0 16px}.card{background:#fff;border:1px solid #e1e8f0;border-radius:24px;padding:26px;box-shadow:0 25px 60px #0f172a14}.brand{color:#64748b;font-weight:700}.area{padding:16px 0;border-bottom:1px solid #edf2f7}.stars{display:flex;flex-direction:row-reverse;justify-content:flex-end;gap:5px}.stars input{display:none}.stars label{font-size:31px;color:#cbd5e1;cursor:pointer}.stars input:checked~label,.stars label:hover,.stars label:hover~label{color:#f59e0b}.field{margin-top:15px}.field label{display:block;font-size:12px;font-weight:800;margin-bottom:6px}.field input,.field textarea{width:100%;padding:12px;border:1px solid #cfd9e5;border-radius:11px;font-family:Poppins}.field textarea{min-height:100px}.btn{width:100%;border:0;border-radius:13px;padding:14px;background:#16a06a;color:#fff;font-weight:800;font-family:Poppins;margin-top:18px;cursor:pointer}.alert{padding:13px;border-radius:12px;background:#fee2e2;color:#991b1b;font-weight:700}.thanks{text-align:center}.score{font-size:42px;font-weight:800;color:#16a06a}.links{display:grid;gap:10px;margin-top:18px}.links a{padding:13px;border-radius:12px;text-decoration:none;font-weight:800;background:#eef2ff;color:#1d4ed8}.private{padding:15px;border-radius:14px;background:#fff7ed;color:#9a3412;margin-top:16px}</style></head><body><main class="wrap"><section class="card"><?php if(!$ok):?><div class="brand"><?=htmlspecialchars($encuesta['nombre_comercial'])?></div><h1><?=htmlspecialchars($encuesta['titulo'])?></h1><p><?=nl2br(htmlspecialchars($encuesta['descripcion']??''))?></p><?php if($err):?><div class="alert"><?=htmlspecialchars($err)?></div><?php endif;?><form method="post"><?php foreach($areas as $a):?><div class="area"><b><?=htmlspecialchars($a['nombre'])?></b><div class="stars"><?php for($i=5;$i>=1;$i--):?><input required type="radio" id="a<?=$a['id_area']?>_<?=$i?>" name="area[<?=$a['id_area']?>]" value="<?=$i?>"><label for="a<?=$a['id_area']?>_<?=$i?>">★</label><?php endfor;?></div></div><?php endforeach;?><div class="field"><label>Nombre (opcional)</label><input name="nombre"></div><div class="field"><label>Email (opcional)</label><input type="email" name="email"></div><div class="field"><label>Comentario</label><textarea name="comentario" placeholder="Cuéntanos qué podemos mejorar..."></textarea></div><button class="btn">Enviar respuesta</button></form><?php else:?><div class="thanks"><h1>¡Gracias por tu opinión!</h1><div class="score"><?=number_format($promedio,1)?> ★</div><?php if($mostrarRedes):?><p>Nos alegra que hayas tenido una buena experiencia. También puedes compartirla públicamente:</p><div class="links"><?php foreach(['google_reviews'=>'Google Reviews','facebook'=>'Facebook','tripadvisor'=>'Tripadvisor','instagram'=>'Instagram','tiktok'=>'TikTok','sitio_web'=>'Sitio web'] as $k=>$l):if(in_array($k,$redesPermitidas??[],true)&&!empty($redes[$k])):?><a target="_blank" rel="noopener" href="<?=htmlspecialchars($redes[$k])?>"><?=$l?></a><?php endif;endforeach;?></div><?php else:?><div class="private">Tu comentario fue registrado de forma interna para que el hotel pueda mejorar.</div><?php endif;?></div><?php endif;?></section></main></body></html>
